// Quebra a resposta do Notion em 1 item por card + calcula dias parado e faixa de dívida
const hoje = new Date();
const out = [];
for (const r of ($input.first().json.results || [])) {
  const p = r.properties || {};
  const txt = (o) => (o?.rich_text?.[0]?.plain_text) || (o?.title?.[0]?.plain_text) || '';
  const num = (o) => (o?.number ?? 0);
  const sel = (o) => (o?.select?.name) || '';
  const dt  = (o) => (o?.date?.start) || null;
  const ultima = dt(p['Última interação']);
  const diasParado = ultima ? Math.floor((hoje - new Date(ultima)) / 86400000) : 999;
  const parcelas = num(p['Parcelas em atraso']);
  const faixa = parcelas <= 2 ? 'Leve' : parcelas <= 5 ? 'Média' : 'Alta';
  out.push({ json: {
    pageId: r.id,
    nome: txt(p['Nome']),
    cpf: txt(p['CPF']),
    valorDevido: num(p['Valor devido']),
    parcelas,
    faixa,
    origem: sel(p['Origem']),
    status: sel(p['Status']),
    dono: sel(p['Dono']),
    tentativas: num(p['Tentativas']),
    diasParado,
    observacoes: txt(p['Observações'])
  }});
}
return out;

