// Junta a resposta da IA com os dados do card (vinda do node 'Prepara cards')
const card = $('Prepara cards (dias parado + faixa)').item.json;
let ai = {};
try {
  const raw = $json.content?.[0]?.text || '{}';
  ai = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || '{}');
} catch (e) { ai = { oferta_sugerida: '', mensagem_sugerida: '', novo_status: card.status, prioridade: 'media', motivo: 'parse-fail' }; }
return { json: { ...card, ...ai } };

// Monta o resumo matinal a partir de todos os cards processados
const items = $input.all().map(i => i.json);
const by = (s) => items.filter(c => (c.novo_status || c.status) === s).length;
const quentes = items
  .filter(c => c.prioridade === 'alta')
  .sort((a,b) => (b.valorDevido||0) - (a.valorDevido||0))
  .slice(0,5);
const parados = items.filter(c => c.diasParado >= 3).length;
const data = new Date().toLocaleDateString('pt-BR');
let msg = `🏭 KANBAN DE DÍVIDAS — ${data}\n\n`;
msg += `📊 Pipeline: Triagem ${by('🆕 Triagem')} · Abordagem ${by('📤 Abordagem enviada')} · Negociação ${by('💬 Em negociação')} · Proposta ${by('📄 Proposta enviada')} · Aceitou ${by('✅ Aceitou')}\n\n`;
msg += `🎯 PRIORIDADES DE HOJE\n`;
msg += `• Karine: ${items.filter(c=>c.dono==='Karine').length} cards\n`;
msg += `• Lucas: ${by('⛔ Processo de cancelamento')} em cancelamento (ligar e encerrar)\n`;
msg += `• Raquel: ${by('🆕 Triagem')} em triagem p/ enriquecer\n\n`;
msg += `🔥 TOP 5 quentes:\n`;
quentes.forEach((c,i) => { msg += `${i+1}. ${c.nome} — R$ ${c.valorDevido} (${c.parcelas}p) — ${c.motivo || ''}\n`; });
msg += `\n⚠️ ${parados} cards parados há +3 dias → cobrar ou cancelar`;
return [{ json: { resumo: msg, total: items.length } }];
